mapper.update:
UPDATE cart
SET f_status = 'Y',
    f_dstatus = 0,
    f_name = #{f_name},
    f_tel = #{f_tel},
    f_addr = #{f_addr}
WHERE c_code = #{c_code}
  AND id = #{id}
  AND f_status = 'N'

UPDATE cart
SET f_dstatus = -1
WHERE c_code = #{c_code}
  AND id = #{id}
  AND f_status = 'Y'
  AND f_dstatus IN (0, 1)

UPDATE cart
SET f_dstatus = #{f_dstatus}
WHERE c_code = #{c_code}
  AND id = #{id}
  AND f_status = 'Y'
